// ==========================================
// ENGAGEMENT ANALYZER
// Analyzes recent posts performance + finds
// unanswered comments to reply to
// ==========================================
const posts = $('Fetch Recent Posts').first()?.json?.data || [];
const insights = $('Fetch Account Insights').first()?.json?.data || [];

const now = new Date();
const threeHoursAgo = new Date(now - 3 * 60 * 60 * 1000);

// Post performance
const postStats = posts.map(p => {
  const postDate = new Date(p.timestamp);
  const hoursAge = Math.round((now - postDate) / (1000 * 60 * 60));
  const engagementRate = p.comments_count + p.like_count;
  return {
    id: p.id,
    caption: (p.caption || '').substring(0, 100),
    likes: p.like_count || 0,
    comments: p.comments_count || 0,
    hours_age: hoursAge,
    engagement: engagementRate,
    is_recent: hoursAge <= 6,
    needs_boost: p.comments_count < 3 && hoursAge <= 12,
    type: p.media_type
  };
});

// Account insights
const insightMap = {};
insights.forEach(i => {
  insightMap[i.name] = i.values?.[0]?.value || 0;
});

// Find posts needing attention
const lowEngagement = postStats.filter(p => p.needs_boost);
const topPost = postStats.sort((a, b) => b.engagement - a.engagement)[0];

// Recommendations
const actions = [];

if (lowEngagement.length > 0) {
  actions.push({
    type: 'boost_comments',
    message: `${lowEngagement.length} بوست تفاعله ضعيف — جرب Pin comment أو Story share`,
    posts: lowEngagement.map(p => p.id)
  });
}

if (topPost && topPost.comments >= 5) {
  actions.push({
    type: 'reply_top_post',
    message: `أفضل بوست عنده ${topPost.comments} تعليق — رد على كل واحد`,
    post_id: topPost.id
  });
}

// Timing recommendation
const hour = now.getHours();
let bestAction = '';
if (hour >= 20 || hour <= 1) bestAction = '🌙 وقت الذروة — انشر Story تفاعلي (استفتاء/سؤال)';
else if (hour >= 6 && hour <= 9) bestAction = '☀️ صباح — انشر Reel أو Carousel';
else if (hour >= 13 && hour <= 15) bestAction = '🕐 وقت الظهر — شارك اقتباس من تمعّن';
else bestAction = '⏳ وقت هادئ — رد على التعليقات + DMs المعلقة';

return {
  json: {
    timestamp: now.toISOString(),
    total_posts_analyzed: postStats.length,
    insights: {
      accounts_engaged: insightMap.accounts_engaged || 'N/A',
      reach: insightMap.reach || 'N/A',
      profile_views: insightMap.profile_views || 'N/A'
    },
    top_post: topPost || null,
    low_engagement_posts: lowEngagement.length,
    actions,
    timing_recommendation: bestAction,
    post_stats: postStats.slice(0, 5)
  }
};

// Find comments we haven't replied to yet
const comments = $('Fetch Unanswered Comments').first()?.json?.data || [];
const analysis = $('Analyze Engagement').first()?.json || {};

const unanswered = comments.filter(c => {
  const hasReplies = c.replies?.data?.length > 0;
  return !hasReplies;
}).slice(0, 5); // Max 5 auto-replies per cycle

return {
  json: {
    ...analysis,
    unanswered_comments: unanswered.map(c => ({
      id: c.id,
      text: c.text,
      username: c.username,
      timestamp: c.timestamp
    })),
    unanswered_count: unanswered.length
  }
};

